n modified functions.\n185:   PA.preserveSet\u003cAllAnalysesOn\u003cFunction\u003e\u003e();\n186:   return PA;\n187: }\n188: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/llvm-project--a8f3c97d@4152de6435984e9fc55431f4d74a7470d8ac05c0/-/blob/llvm/lib/Transforms/IPO/AlwaysInliner.cpp"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: //===- AlwaysInliner.cpp - Code to inline always_inline functions ----------===//
